function calculateMasteryLevel(
  correctAttempts: number,
  totalAttempts: number,
  consecutiveCorrect: number
): WordPerformance["masteryLevel"] {
  if (totalAttempts === 0) return "learning";

  const accuracy = correctAttempts / totalAttempts;

  if (accuracy >= 0.9 && consecutiveCorrect >= 3) return "mastered";
  if (accuracy >= 0.7 && consecutiveCorrect >= 2) return "proficient";
  if (accuracy >= 0.5) return "learning";
  return "struggling";
}

function escapeRegex(value: string) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function sentenceContainsWord(sentence: string, word: string) {
  return new RegExp(`\\b${escapeRegex(word)}\\b`, "i").test(sentence);
}

function fallbackSentenceFeedback(
  sentence: string,
  word: VocabularyWord
): SentenceFeedback {
  const trimmedSentence = sentence.trim();
  const wordCount = trimmedSentence.split(/\s+/).filter(Boolean).length;
  const includesWord = sentenceContainsWord(trimmedSentence, word.word);

  if (!includesWord) {
    return {
      correct: false,
      exampleSentence: word.example,
      aiResponse: `Your sentence needs to include "${word.word}" as the target word.`,
      hint: `Try writing a complete sentence that uses "${word.word}" with the meaning "${word.definition}".`,
    };
  }

  if (wordCount < 5) {
    return {
      correct: false,
      exampleSentence: word.example,
      exampleSentence: word.example,
      aiResponse:
        "This is a start, but it is too short to show the word's meaning clearly.",
      hint: "Add enough context to show what the word means in a real situation.",
